#!/bin/sh

# Xcode Cloud post-clone hook.
#
# VoCal.xcodeproj is generated by XcodeGen from project.yml and is gitignored
# (.gitignore: *.xcodeproj). A fresh Xcode Cloud clone therefore has only
# project.yml, so the build fails with:
#     Project VoCal.xcodeproj does not exist at apps/ios/VoCal.xcodeproj
# Regenerate the project here, before Xcode Cloud resolves packages and builds.
#
# Xcode Cloud runs this automatically after cloning the primary repository,
# because it lives in apps/ios/ci_scripts/ (the folder containing the project).

set -e

echo "[ci_post_clone] installing xcodegen via Homebrew…"
brew install xcodegen

echo "[ci_post_clone] generating VoCal.xcodeproj from project.yml…"
cd "$CI_PRIMARY_REPOSITORY_PATH/apps/ios"
xcodegen generate

echo "[ci_post_clone] done: $(ls -d VoCal.xcodeproj)"
